func (f *CommandFactory) runMetricHistoryCommand(cmd *cobra.Command, args []string) error {
	groups, err := f.metricStore().GroupedHistory(args[0])
	if err != nil {
		return err
	}
	if cmd.Flags().Changed("json") {
		enc := json.NewEncoder(cmd.OutOrStdout())
		enc.SetIndent("", "  ")
		return enc.Encode(groups)
	}
	for _, group := range groups {

	for _, group := range groups {
		unit := group.Unit
		if unit == "" {
			unit = "(none)"
		}
		fmt.Fprintf(cmd.OutOrStdout(), "unit: %s\n", unit)
		for _, rec := range group.Records {
			fmt.Fprintf(cmd.OutOrStdout(), "  %s  %s  %.3f%s  %s\n", rec.ObservedAt.Format(time.RFC3339), rec.RunID, rec.Value, rec.Unit, rec.Status)
		}
	}
	return nil
}

func (f *CommandFactory) runMetricTrendCommand(cmd *cobra.Command, args []string) error {
	summary, err := f.metricStore().Trend(args[0])
	if err != nil {
		return err
	}
	if cmd.Flags().Changed("json") {
		enc := json.NewEncoder(cmd.OutOrStdout())
		enc.SetIndent("", "  ")
		return enc.Encode(summary)
	}
	fmt.Fprintf(cmd.OutOrStdout(), "%s  count=%d  avg=%.3f%s  min=%.3f  max=%.3f\n", summary.MetricID, summary.Count, summary.Average, summary.Unit, summary.Min, summary.Max)
	return nil
}

func joinCommand(parts []string) string {
	if len(parts) == 0 {
		return "(none)"
	}
	return strings.Join(parts, " ")
}

